import React from 'react';
import { LogisticsEvent, LogisticsType } from '../types';
import { LOGISTICS_TYPES } from '../constants';

interface MonthViewProps {
  currentDate: Date;
  events: LogisticsEvent[];
  activeFilters: LogisticsType[];
  onEventClick: (event: LogisticsEvent) => void;
}

const MonthView: React.FC<MonthViewProps> = ({ currentDate, events, activeFilters, onEventClick }) => {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const firstDayOfMonth = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  const days = [];
  // Previous month padding
  for (let i = 0; i < firstDayOfMonth; i++) days.push(null);
  // Current month days
  for (let i = 1; i <= daysInMonth; i++) days.push(i);

  const getDayEvents = (day: number) => {
    return events.filter(e => {
      const eDate = new Date(e.start);
      return eDate.getDate() === day && eDate.getMonth() === month && eDate.getFullYear() === year && activeFilters.includes(e.type);
    });
  };

  const getEventColor = (type: LogisticsType) => {
    return LOGISTICS_TYPES.find(t => t.value === type)?.color || 'bg-slate-400';
  };

  return (
    <div className="flex-1 overflow-hidden flex flex-col">
      <div className="grid grid-cols-7 border-b border-slate-200">
        {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
          <div key={day} className="py-2 text-center text-xs font-semibold text-slate-500 uppercase tracking-wider border-r border-slate-100 last:border-0">
            {day}
          </div>
        ))}
      </div>
      <div className="flex-1 grid grid-cols-7 auto-rows-fr overflow-y-auto custom-scrollbar">
        {days.map((day, idx) => (
          <div key={idx} className={`min-h-[120px] border-r border-b border-slate-100 p-1 group hover:bg-slate-50 transition-colors ${day === null ? 'bg-slate-50/50' : ''}`}>
            {day && (
              <>
                <div className="flex justify-center mb-1">
                  <span className={`text-xs font-medium w-7 h-7 flex items-center justify-center rounded-full transition-colors
                    ${day === new Date().getDate() && month === new Date().getMonth() ? 'bg-blue-600 text-white' : 'text-slate-700 group-hover:bg-slate-200'}
                  `}>
                    {day}
                  </span>
                </div>
                <div className="space-y-1">
                  {getDayEvents(day).map(event => (
                    <button
                      key={event.id}
                      onClick={() => onEventClick(event)}
                      className={`w-full text-left px-2 py-0.5 text-[10px] leading-tight text-white rounded truncate transition-all hover:brightness-110 active:scale-95 ${getEventColor(event.type)}`}
                    >
                      <span className="font-bold mr-1">{event.type === 'Maritime' ? '🚢' : event.type === 'Road' ? '🚛' : event.type === 'Rail' ? '🚆' : '✈️'}</span>
                      {event.title}
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default MonthView;

import React, { useState } from 'react';
import { SparklesIcon } from './Icons';
import { getLogisticsIntelligence } from '../services/geminiService';
import { LogisticsEvent } from '../types';

interface AIAssistantProps {
  events: LogisticsEvent[];
}

const AIAssistant: React.FC<AIAssistantProps> = ({ events }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState<{ role: 'user' | 'ai'; text: string }[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleSend = async () => {
    if (!query.trim()) return;
    const userMsg = query;
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setQuery('');
    setIsLoading(true);

    const response = await getLogisticsIntelligence(userMsg, events);
    setMessages(prev => [...prev, { role: 'ai', text: response || '' }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {isOpen ? (
        <div className="bg-white rounded-2xl shadow-2xl border border-slate-200 w-80 md:w-96 flex flex-col max-h-[500px] animate-in fade-in slide-in-from-bottom-4 duration-300">
          <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-blue-600 rounded-t-2xl text-white">
            <div className="flex items-center space-x-2">
              <SparklesIcon />
              <span className="font-bold">EuroLogix Intelligence</span>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-blue-700 rounded p-1 transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar min-h-[200px]">
            {messages.length === 0 && (
              <div className="text-center text-slate-400 text-sm mt-8 px-4">
                Ask about port strikes, transit times between EU cities, or shipment delays.
              </div>
            )}
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] rounded-2xl px-3 py-2 text-sm ${
                  m.role === 'user' ? 'bg-blue-600 text-white rounded-br-none' : 'bg-slate-100 text-slate-800 rounded-bl-none'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-slate-100 rounded-2xl px-3 py-2 text-sm animate-pulse flex space-x-1">
                  <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce" />
                  <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.2s]" />
                  <div className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.4s]" />
                </div>
              </div>
            )}
          </div>

          <div className="p-4 border-t border-slate-100">
            <div className="flex space-x-2">
              <input 
                value={query}
                onChange={e => setQuery(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSend()}
                placeholder="Ask logistics AI..."
                className="flex-1 bg-slate-50 border border-slate-200 rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
              <button 
                onClick={handleSend}
                disabled={isLoading}
                className="bg-blue-600 text-white p-2 rounded-full hover:bg-blue-700 transition-colors disabled:opacity-50"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
              </button>
            </div>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-blue-600 text-white p-4 rounded-full shadow-lg hover:shadow-xl hover:scale-105 transition-all flex items-center space-x-2"
        >
          <SparklesIcon />
          <span className="font-medium hidden sm:inline">Logistics AI</span>
        </button>
      )}
    </div>
  );
};

